import { Push, Pull, None, none, taken } from './stream';

const now: () => number =
    Date.now ? () => Date.now() :
        () => new Date().getTime();

export function interval(period: number): Pull<None> {
    let time = now();

    const pull_ = (push: Push<None>) => {
        const pre_ = time;

        time = now();
        const timer = setTimeout(() => {
            time = now();
            push(none, pull_);
        }, Math.max(0, period - (time - pre_)));

        return () => {
            clearTimeout(timer);

            time = pre_;

            return pull_;
        };
    };

    return pull_;
}

export function timeout(delay: number): Pull<None> {
    return taken(1, interval(delay));
}
